		VERSION_BASE,
		VERSION_CURRENT = VERSION_BASE,
	};
	CVersion V( ar, VERSION_CURRENT );

	// serialize out the IP Address data.
	if( ar.IsStoring() ) {
		CString IP;
		UINT	Port=0;

		RetrieveAddress( IP, Port );
		ar << IP;
		ar << Port;

		GetDeviceName( IP );
		ar << IP;

	} else {
		CString IP;
		UINT	Port=0;

		ar >> IP;
		ar >> Port;
		SetAddress( IP, Port );

		ar >> IP;
		SetDeviceName( IP );
	}
}

