const int PCRE_OPTION_COUNT = 9;

DTPCRECompilationOptions InputValidatorPCRE::sm_PCRECompilationOptions[] = {
0,	PCRE_UNGREEDY,		"UNGREEDY",
1,	PCRE_DOTALL,			"DOTALL",
2,	PCRE_NO_AUTO_CAPTURE,	"NO_AUTO_CAPTURE",
