                if len(p.name) > longest:
                    longest = len(p.name)
                results.append((p.name, getattr(details, p.name)))

        if not results:
            self.logger.error("ERROR: No attributes on", details)

        for name, val in results:
            self.logger.info("%*s: %s" % (longest, name, val))

