{
	if( STATE_DATA_TRANSFER_XON == lgo_State( m_CIDPacket ) &&
		STATE_DATA_TRANSFER_XON == lgo_State( m_CIDLink ) &&
		STATE_DATA_TRANSFER_XON == lgo_State( m_CIDPhysical ) )
	{
		return true;
	}
	return false;
}

